{
  "name": "hello-rainbow-ui-req",
  "version": "0.1.0",
  "private": true,
  "description": "A small project demonstrating a Hello World rainbow UI with a tiny TypeScript dev server",
  "scripts": {
    "test": "jest --runInBand",
    "build": "tsc",
    "start": "node dist/server.js",
    "dev": "ts-node src/server.ts",
    "serve": "npm run build && npm start"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "typescript": "^5.2.2",
    "ts-node": "^10.9.1",
    "ts-jest": "^29.1.0",
    "jest": "^29.5.0",
    "@types/express": "^4.17.17",
    "@types/jest": "^29.5.3",
    "supertest": "^6.3.3",
    "@types/supertest": "^2.0.12"
  }
}

import express from 'express';
import path from 'path';

const app = express();
const PORT = process.env.PORT || 3000;

// Serve the public directory (static files)
const publicDir = path.join(__dirname, '..', 'public');
app.use(express.static(publicDir));

// Ensure root serves index.html explicitly
app.get('/', (req, res) => {
  res.sendFile(path.join(publicDir, 'index.html'));
});

if (require.main === module) {
  app.listen(PORT, () => {
    // eslint-disable-next-line no-console
    console.log(`Server listening on http://localhost:${PORT}`);
  });
}

export default app;

/* Basic layout */
:root{
  --bg: #0f172a;
}
html,body{height:100%;}
body{
  margin:0;
  display:flex;
  align-items:center;
  justify-content:center;
  background:var(--bg);
  color:#e6eef8;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
}
main{text-align:center;padding:2rem}

/* Default heading styles */
.hello{
  font-size:3rem;
  margin:0.2rem 0 1rem 0;
  line-height:1.1;
  font-weight:700;
  color: #fff; /* fallback */
}

/* Rainbow text effect - uses gradient clipped to text */
.rainbow{
  background: linear-gradient(90deg, #ff004f, #ff7a00, #ffdd00, #00c853, #00b0ff, #7c4dff);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  animation: rainbowShift 4s linear infinite;
  background-size: 300% 100%;
}

@keyframes rainbowShift{
  0%{background-position:0% 50%}
  50%{background-position:100% 50%}
  100%{background-position:0% 50%}
}

button{padding:0.4rem 0.8rem;border-radius:6px;border:none;background:#1f2937;color:#fff;cursor:pointer}
.note{opacity:0.8;font-size:0.9rem}

/* Frontend helper to toggle/apply rainbow class to the Hello World heading.
   The element is targetable by id="hello" and class="hello".
*/
(function(){
  function addRainbow() {
    const el = document.getElementById('hello');
    if (!el) return;
    el.classList.add('rainbow');
  }

  function removeRainbow() {
    const el = document.getElementById('hello');
    if (!el) return;
    el.classList.remove('rainbow');
  }

  function toggleRainbow() {
    const el = document.getElementById('hello');
    if (!el) return;
    el.classList.toggle('rainbow');
  }

  document.addEventListener('DOMContentLoaded', function(){
    // Apply rainbow effect by default on load
    addRainbow();

    const btn = document.getElementById('toggleRainbow');
    if (btn) btn.addEventListener('click', toggleRainbow);
  });
})();

import request from 'supertest';
import app from '../src/server';

describe('GET /', () => {
  it('responds with HTML containing the exact Hello World heading and id/class', async () => {
    const res = await request(app).get('/').expect(200).expect('Content-Type', /html/);
    const body: string = res.text;

    // Must contain exact text
    expect(body).toEqual(expect.stringContaining('Hello World'));

    // Heading element with id="hello"
    expect(body).toMatch(/<h1[^>]*id=["']hello["'][^>]*>\s*Hello World\s*<\/h1>/);

    // Ensure script and stylesheet are referenced so JS/CSS can target the element
    expect(body).toEqual(expect.stringContaining('styles.css'));
    expect(body).toEqual(expect.stringContaining('app.js'));
  });
});
